sys_script_include.script:
function BusinessProcessValidate(business_process, bDetailed)
{
	bDetailed = GetBoolValue(bDetailed);

	var result = {};
	result.valid = true;
	result.errors = [];
	result.warnings = [];
	result.notes = [];

	function GetResult()
	{
		if (result.errors.length > 0)
		{
			result.valid = false;
		}
		if (bDetailed == true)
		{
			return result;
		}
		return result.valid;
	}

	if (IsObject(business_process) == false)
	{
		result.errors.push('Provided parameter is not an object.');
		return GetResult();
	}

	if (IsEqual(business_process,{}) == true)
	{
		result.errors.push('Provided object is empty.');
		return GetResult();
	}

	var strId = GetStringValue(GetValue(business_process,'id'));
	if (strId == '')
	{
		result.errors.push('No Business Process ID (i.e. technical name) was provided ("id").');		
	}

	var strName = GetStringValue(GetValue(business_process,'name'));
	if (strName == '')
	{
		result.errors.push('No Business Process name was provided ("name").');		
	}	

	var strDescription = GetStringValue(GetValue(business_process,'description'));
	if (strDescription == '')
	{
		result.warnings.push('No Business Process description text has been provided ("description").');		
	}

	var aRoles = GetArrayValue(GetValue(business_process,'_roles'));
	if (aRoles.length == 0)
	{
		result.errors.push('No process roles have been defined ("_roles").');
	}

	var aStates = GetArrayValue(GetValue(business_process,'_states'));
	if (aStates.length == 0)
	{
		result.errors.push('No states have been defined ("_states").');
	}



	return GetResult();
}
